{"content": "import { readFileSync, existsSync, readdirSync } from 'fs'
import path from 'path'
import Head from 'next/head'

function resolveContent(content: any, key: string): any {
  if (!content || !key) return null
  let sc = content[key]
  if (!sc && key.includes('.')) sc = key.split('.').reduce((o: any, k: string) => o?.[k], content)
  return sc
}

function renderSection(section: any, content: any, idx: number) {
  const key = section.content || section.id || 's' + idx
  if (section.enabledWhen && !resolveContent(content, section.enabledWhen)) return null
  let sc = resolveContent(content, key)
  if (!sc && section.id) sc = resolveContent(content, section.id)
  if (!sc) return null

  if (typeof sc === 'string') return <section key={key} style={{padding:'1rem',margin:'0.5rem 0',background:'#f4f4f4',borderRadius:'6px'}}><p>{sc}</p></section>

  if (Array.isArray(sc)) {
    return (
      <section key={key} style={{padding:'1.5rem 0'}}>
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(300px,1fr))',gap:'1.25rem'}}>
          {sc.map((item: any, i: number) => (
            <div key={i} style={{padding:'1.25rem',borderRadius:'8px',background:'#f8f9fa'}}>
              {item.title && <h3 style={{fontSize:'1.15rem',fontWeight:600,marginBottom:'0.5rem'}}>{item.title}</h3>}
              {item.description && <p style={{color:'#555',lineHeight:1.5}}>{item.description}</p>}
              {item.price && <p style={{fontSize:'1.1rem',fontWeight:700,color:'#0a0',marginTop:'0.5rem'}}>{item.price}</p>}
            </div>
          ))}
        </div>
      </section>
    )
  }

  if (typeof sc === 'object' && !Array.isArray(sc)) {
    return (
      <section key={key} style={{padding:'2rem 0'}}>
        <div style={{maxWidth:'800px',margin:'0 auto',textAlign:'center'}}>
          {sc.headline && <h2 style={{fontSize:'1.75rem',fontWeight:'bold',marginBottom:'0.75rem'}}>{sc.headline}</h2>}
          {sc.subheadline && <p style={{fontSize:'1.1rem',color:'#666',lineHeight:1.6,marginBottom:'1rem'}}>{sc.subheadline}</p>}
          {sc.title && <h2 style={{fontSize:'1.5rem',fontWeight:600,marginBottom:'0.75rem'}}>{sc.title}</h2>}
          {sc.eyebrow && <p style={{fontSize:'0.85rem',color:'#999',textTransform:'uppercase',letterSpacing:'1px',marginBottom:'0.5rem'}}>{sc.eyebrow}</p>}
          {sc.description && <p style={{color:'#555',marginBottom:'0.5rem'}}>{sc.description}</p>}
          {sc.ctaPrimaryText && (
            <a href={sc.ctaPrimaryHref || '#'} style={{display:'inline-block',padding:'0.75rem 2rem',background:'#1B2A4A',color:'#fff',borderRadius:'8px',textDecoration:'none',fontWeight:600,margin:'0.5rem'}}>
              {sc.ctaPrimaryText}
            </a>
          )}
          {sc.ctaSecondaryText && (
            <a href={sc.ctaSecondaryHref || '#'} style={{display:'inline-block',padding:'0.75rem 2rem',border:'2px solid #1B2A4A',color:'#1B2A4A',borderRadius:'8px',textDecoration:'none',fontWeight:600,margin:'0.5rem'}}>
              {sc.ctaSecondaryText}
            </a>
          )}
          {sc.items && Array.isArray(sc.items) && sc.items.map((item: any, j: number) => (
            <div key={j} style={{padding:'1rem',borderBottom:'1px solid #eee',textAlign:'left'}}>
              {item.title && <h4 style={{fontWeight:600,marginBottom:'0.25rem'}}>{item.title}</h4>}
              {item.description && <p style={{color:'#555',fontSize:'0.95rem'}}>{item.description}</p>}
              {item.quote && <p style={{fontStyle:'italic',color:'#666'}}>"{item.quote}"</p>}
            </div>
          ))}
        </div>
      </section>
    )
  }
  return null
}

export default function Page({ content, pageConfig, pageId }: any) {
  const siteName = content?.siteName || 'Nexa Paraguay'
  const sections = pageConfig?.sections || []
  const seo = resolveContent(content, (pageConfig?.seoTitle || pageId + '.seo'))
  const pageTitle = seo?.title || pageConfig?.title || siteName
  const pageDesc = seo?.description || pageConfig?.description || ''

  return (
    <>
      <Head>
        <title>{pageTitle}</title>
        {pageDesc && <meta name="description" content={pageDesc} />}
      </Head>
      <main style={{maxWidth:'1200px',margin:'0 auto',padding:'2rem 1rem'}}>
        <h1 style={{fontSize:'2rem',fontWeight:'bold',textAlign:'center',padding:'3rem 0'}}>{siteName}</h1>
        {sections.map((section: any, idx: number) => renderSection(section, content, idx))}
      </main>
    </>
  )
}

